mapper.select:
select

from plant_single_stock_tb

    and plant_code=#{plantCode,jdbcType=VARCHAR}
    and generation=#{generation,jdbcType=VARCHAR}
    and plant_number=#{plantNumber,jdbcType=NUMERIC}
    and plant_date=#{plantDate,jdbcType=VARCHAR}
    and sample_code=#{sampleCode,jdbcType=VARCHAR}
    and transplant_date=#{transplantDate,jdbcType=VARCHAR}

        and  vernalization_begin_date=#{vernalizationBeginDate,jdbcType=VARCHAR}

    and vernalization_end_date=#{vernalizationEndDate,jdbcType=VARCHAR}

    and pollination_method=#{pollinationMethod,jdbcType=VARCHAR}
    and plant_status=#{plantStatus,jdbcType=VARCHAR}
    and pollination_date=#{pollinationDate,jdbcType=VARCHAR}
    and harvest_date=#{harvestDate,jdbcType=VARCHAR}
    and harvest_type=#{harvestType,jdbcType=VARCHAR}
    and other_field=#{otherField}
    and edit_type=#{editType,jdbcType=VARCHAR}
    and species_code=#{speciesCode,jdbcType=VARCHAR}
    and create_date=#{createDate,jdbcType=TIMESTAMP}
    and update_time=#{updateTime,jdbcType=TIMESTAMP}
    and create_user_id=#{createUserId,jdbcType=NUMERIC}
    and create_user_name=#{createUserName,jdbcType=VARCHAR}
    and task_num=#{taskNum,jdbcType=VARCHAR}
    and breed_code=#{breedCode,jdbcType=VARCHAR}
    and source_code=#{sourceCode,jdbcType=VARCHAR}
    and remark=#{remark,jdbcType=VARCHAR}
    and vector_task_code=#{vectorTaskCode,jdbcType=VARCHAR}

order by id desc
